import{_ as t,c as o,o as i,aq as a}from"./chunks/framework.jeRwkH3J.js";const s="/manuals/guides/getting-started/add-to-favourites.jpg",h=JSON.parse('{"title":"Getting started","description":"Essential information to help you get set up with Usagi.","frontmatter":{"title":"Getting started","description":"Essential information to help you get set up with Usagi.","footer":false},"headers":[],"relativePath":"manuals/guides/getting-started/index.md","filePath":"manuals/guides/getting-started/index.md","lastUpdated":1776351251000,"breadcrumbs":[{"text":"User manual","link":"/manuals/guides/getting-started/"},{"text":"Guides","items":[{"text":"Getting started","link":"/manuals/guides/getting-started/"},{"text":"Troubleshooting","link":"/manuals/guides/troubleshooting/","collapsed":true,"items":[{"text":"Common issues","link":"/manuals/guides/troubleshooting/common-issues/"},{"text":"Diagnosis","link":"/manuals/guides/troubleshooting/diagnosis/"}]},{"text":"Backups","link":"/manuals/guides/backups/"},{"text":"Tracking","link":"/manuals/guides/tracking/"},{"text":"Categories","link":"/manuals/guides/categories/"},{"text":"Synchronization","link":"/manuals/guides/synchronization/"}]},{"text":"Getting started","link":"/manuals/guides/getting-started/"}]}'),n={name:"manuals/guides/getting-started/index.md"};function r(l,e,u,d,g,c){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h1><p>Essential information to help you get set up with Usagi.</p><h2 id="installation-guide" tabindex="-1">Installation guide <a class="header-anchor" href="#installation-guide" aria-label="Permalink to &quot;Installation guide&quot;">​</a></h2><h3 id="downloading-usagi" tabindex="-1">Downloading Usagi <a class="header-anchor" href="#downloading-usagi" aria-label="Permalink to &quot;Downloading Usagi&quot;">​</a></h3><ol><li>Visit our <a href="/download/">download</a> page to get the latest version of <strong>Usagi</strong>.</li><li>After the download is complete, open the <code>release.apk</code> file.</li><li>Proceed with the installation process.</li></ol><h3 id="importing-source-plugins-optional" tabindex="-1">Importing source plugins (optional) <a class="header-anchor" href="#importing-source-plugins-optional" aria-label="Permalink to &quot;Importing source plugins (optional)&quot;">​</a></h3><p>Usagi does not include preloaded online sources. You can import any external plugin that is compatible with <a href="https://github.com/UsagiApp/core-exts" target="_blank" rel="noreferrer">core-exts</a> library.</p><ol><li>Go to <strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong>.</li><li>Tap <strong>+</strong> and choose: <ul><li><strong>Import from GitHub</strong>: enter <code>owner/repository</code>. Usagi will install a <code>.jar</code> from the latest release.</li><li><strong>Import from local storage</strong>: pick a local <code>.jar</code> plugin file.</li></ul></li><li>After import succeeds, open <strong>Sources Catalog</strong> and enable the sources you want to use.</li></ol><h3 id="adding-series-to-your-favourites" tabindex="-1">Adding series to your favourites <a class="header-anchor" href="#adding-series-to-your-favourites" aria-label="Permalink to &quot;Adding series to your favourites&quot;">​</a></h3><p>Here&#39;s how you can add series to your favourites:</p><ol><li>Select the source you&#39;d like to browse.</li><li>Once you&#39;ve found the series that you want to add, tap on it for more details.</li><li>Press the &quot;Favourite this&quot; chip, choose category or create new one, and the series will be added to your favourites.</li></ol><img src="'+s+'" alt="Adding to favourites" width="500"><h2 id="additional-setup" tabindex="-1">Additional setup <a class="header-anchor" href="#additional-setup" aria-label="Permalink to &quot;Additional setup&quot;">​</a></h2><h3 id="series-search-options" tabindex="-1">Series search options <a class="header-anchor" href="#series-search-options" aria-label="Permalink to &quot;Series search options&quot;">​</a></h3><p>If you want to search for series across all your sources, you can use the Global Search feature.</p><p>Follow these steps:</p><ol><li>Go to the main section.</li><li>Use the search bar in the toolbar to find series from all available sources.</li></ol><h3 id="trouble-finding-a-specific" tabindex="-1">Trouble finding a specific series? <a class="header-anchor" href="#trouble-finding-a-specific" aria-label="Permalink to &quot;Trouble finding a specific series?&quot;">​</a></h3><p>If you encounter difficulties while searching for a specific series, consider the following points:</p><ul><li><p>Double-check your spelling and try again, as some sources might use <strong>Japanese romanized</strong> titles instead of <strong>English</strong> ones.</p><blockquote><p>Example: <strong>Boku no Hero Academia</strong> instead of <strong>My Hero Academia</strong>.</p></blockquote></li><li><p>Some sources may use different spellings or wordings for titles.</p><blockquote><p>Example: <strong>Bungo Stray Dogs</strong> instead of <strong>Bungou Stray Dogs</strong>.</p></blockquote><blockquote><p>Example: <strong>3-gatsu no Lion</strong> instead of <strong>Sangatsu no Lion</strong>.</p></blockquote></li></ul>',20)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
